MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE sm HAS_SEMANTIC_ID :SemanticConcept {id: 'https://admin-shell.io/idta/SubmodelTemplate/technicaldataagv/1/0'}
RETURN aas.idShort, aas.id, sm.idShort, sm.id

// Get the template structure for HierarchicalStructures
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el), el.value

// Get all elements in Hall3's hierarchical structures
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el), el.value

// Get facility info for both halls
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

// Get facility info for Hall3
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

// List all properties from MiR250_001 nameplate
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

// Get technical data from MiR250 type AGV submodel
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

// Get technical data from MiR100 type AGV submodel
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE sm HAS_SEMANTIC_ID :SemanticConcept {id: 'https://admin-shell.io/idta/SubmodelTemplate/technicaldataagv/1/0'}
RETURN aas.idShort, aas.id, sm.idShort, sm.id

// Find all AAS shells and their assets, looking for transport robots in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Find all AAS shells and their assets, looking for transport robots
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Check the CapabilityDescription submodel for status indicators
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:capabilitydescription'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, el.value, labels(el) AS types

// Find all AAS shells and their assets to identify the transport robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Explore the HierarchicalStructures submodel contents
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el), el.entityType AS entityType

// Explore the TechnicalDataAGV submodel for any status-related properties
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:technicaldataagv'})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Check the CapabilityDescription submodel
MATCH (sm:Submodel {id: 'urn:submodel:mir100:type:capabilitydescription'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types

// Find all AAS shells and their assets to identify transport robots in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetKind

// Broad traversal of Hall4's HierarchicalStructures submodel
MATCH (sm:Submodel {id: "urn:submodel:hall4:hierarchicalstructures"})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.entityType

// Explore the CapabilityDescription submodel on MiR100 Type
MATCH (sm:Submodel {id: "urn:submodel:mir100:type:capabilitydescription"})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.value

// Explore the TechnicalDataAGV submodel on MiR100 Type
MATCH (sm:Submodel {id: "urn:submodel:mir100:type:technicaldataagv"})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.value
